```rust
use std::process::Command;
use tokio::net::TcpListener;

/// Test server wrapper that manages lifecycle
pub struct TestServer {
    server: Server,
    port: u16,
    shutdown: oneshot::Sender<()>,
}

impl TestServer {
    pub async fn start() -> Self {
        // Find available port
        let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
        let port = listener.local_addr().unwrap().port();
        drop(listener);

        let config = ServerConfig::builder()
            .bind_addr(format!("127.0.0.1:{}", port))
            .build()
            .unwrap();

        let (shutdown_tx, shutdown_rx) = oneshot::channel();
        let server = Server::new(config)
            .with_auth(AcceptAllAuth)
            .with_bubbletea(|_| TestApp::new());

        // Start server in background
        let server_handle = server.clone();
        tokio::spawn(async move {
            tokio::select! {
                result = server_handle.listen_and_serve() => {
                    if let Err(e) = result {
                        eprintln!("Server error: {}", e);
                    }
                }
                _ = shutdown_rx => {}
            }
        });

        // Wait for server to be ready
        wait_for_port(port).await;

        Self { server, port, shutdown: shutdown_tx }
    }

    pub fn port(&self) -> u16 {
        self.port
    }

    pub async fn stop(self) {
        let _ = self.shutdown.send(());
    }
}

async fn wait_for_port(port: u16) {
    for _ in 0..50 {
        if TcpStream::connect(format!("127.0.0.1:{}", port)).await.is_ok() {
            return;
        }
        tokio::time::sleep(Duration::from_millis(100)).await;
    }
    panic!("Server did not start in time");
}
```

### SSH Client Wrapper
```rust
pub struct SshClient {
    port: u16,
}

impl SshClient {
    pub fn new(port: u16) -> Self {
        Self { port }
    }

    /// Execute SSH command and return output
    pub fn exec(&self, command: &str) -> std::io::Result<Output> {
        Command::new("ssh")
            .args([
                "-o", "StrictHostKeyChecking=no",
                "-o", "UserKnownHostsFile=/dev/null",
                "-o", "BatchMode=yes",
                "-p", &self.port.to_string(),
                "testuser@127.0.0.1",
                command,
            ])
            .output()
    }

    /// Connect with PTY for interactive session
    pub fn connect_interactive(&self) -> std::io::Result<Child> {
        Command::new("ssh")
            .args([
                "-tt",  // Force PTY allocation
                "-o", "StrictHostKeyChecking=no",
                "-o", "UserKnownHostsFile=/dev/null",
                "-p", &self.port.to_string(),
                "testuser@127.0.0.1",
            ])
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .spawn()
    }
}
```

