    #[tokio::test]
    async fn test_concurrent_connections() {
        let server = TestServer::start().await;

        let mut handles = vec![];
        for i in 0..10 {
            let port = server.port();
            handles.push(tokio::spawn(async move {
                let client = SshClient::new(port);
                let output = client.exec(&format!("echo conn{}", i)).unwrap();
                assert!(output.status.success());
            }));
        }

        for handle in handles {
            handle.await.unwrap();
        }

        server.stop().await;
    }

    #[tokio::test]
    async fn test_graceful_shutdown() {
        let server = TestServer::start().await;
        let client = SshClient::new(server.port());

        // Start long-running connection
        let mut child = client.connect_interactive().unwrap();

        // Initiate graceful shutdown
        let shutdown_future = server.shutdown_graceful(Duration::from_secs(5));

        // Connection should be closed gracefully
        let status = child.wait().unwrap();
        assert!(status.success() || status.code() == Some(255)); // SSH exit codes

        shutdown_future.await.unwrap();
    }

    #[tokio::test]
    async fn test_bubbletea_rendering() {
        let server = TestServer::start_with_app(CounterApp::new()).await;
        let client = SshClient::new(server.port());

        let mut child = client.connect_interactive().unwrap();
        let stdin = child.stdin.as_mut().unwrap();
        let mut stdout = BufReader::new(child.stdout.take().unwrap());

        // Wait for initial render
        let initial = read_until_stable(&mut stdout).await;
        assert!(initial.contains("Count: 0"));

        // Send key to increment
        stdin.write_all(b"+").unwrap();

        // Check updated render
        let updated = read_until_stable(&mut stdout).await;
        assert!(updated.contains("Count: 1"));

        child.kill().unwrap();
        server.stop().await;
    }
}
