### 2. Flexible Color Serialization
Support multiple color formats in serialization:

```rust
use serde::{Serialize, Deserialize, Serializer, Deserializer};
use serde::de::{self, Visitor};

/// Color that can be serialized in multiple formats
#[derive(Debug, Clone)]
pub struct SerializableColor(pub Color);

impl Serialize for SerializableColor {
    fn serialize<S: Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
        // Always serialize as hex string for readability
        serializer.serialize_str(&self.0.to_hex())
    }
}

impl<'de> Deserialize<'de> for SerializableColor {
    fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
        deserializer.deserialize_any(ColorVisitor)
    }
}

struct ColorVisitor;

impl<'de> Visitor<'de> for ColorVisitor {
    type Value = SerializableColor;

    fn expecting(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "a color string (hex, rgb, hsl) or color object")
    }

    // Accept hex string: "#ff0000" or "ff0000"
    fn visit_str<E: de::Error>(self, v: &str) -> Result<Self::Value, E> {
        Color::parse(v)
            .map(SerializableColor)
            .map_err(|e| E::custom(format!("invalid color '{}': {}", v, e)))
    }

    // Accept ANSI color number: 196
    fn visit_u64<E: de::Error>(self, v: u64) -> Result<Self::Value, E> {
        if v <= 255 {
            Ok(SerializableColor(Color::Ansi(v as u8)))
        } else {
            Err(E::custom(format!("ANSI color must be 0-255, got {}", v)))
        }
    }

    // Accept object: { "r": 255, "g": 0, "b": 0 }
    fn visit_map<M: de::MapAccess<'de>>(self, mut map: M) -> Result<Self::Value, M::Error> {
        let mut r = None;
        let mut g = None;
        let mut b = None;
        let mut a = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "r" | "red" => r = Some(map.next_value()?),
                "g" | "green" => g = Some(map.next_value()?),
                "b" | "blue" => b = Some(map.next_value()?),
                "a" | "alpha" => a = Some(map.next_value()?),
                _ => { let _ = map.next_value::<de::IgnoredAny>()?; }
            }
        }

        match (r, g, b) {
            (Some(r), Some(g), Some(b)) => {
                let color = match a {
                    Some(a) => Color::rgba(r, g, b, a),
                    None => Color::rgb(r, g, b),
                };
                Ok(SerializableColor(color))
            }
            _ => Err(de::Error::custom("RGB color requires r, g, b fields")),
        }
    }
}
```

### 3. File Format Support
Implement loading from various formats:

```rust
impl Theme {
    /// Load theme from JSON string
    pub fn from_json(json: &str) -> Result<Self, ThemeLoadError> {
        serde_json::from_str(json).map_err(ThemeLoadError::Json)
    }

    /// Load theme from TOML string
    pub fn from_toml(toml: &str) -> Result<Self, ThemeLoadError> {
        toml::from_str(toml).map_err(ThemeLoadError::Toml)
    }

    /// Load theme from YAML string
    #[cfg(feature = "yaml")]
    pub fn from_yaml(yaml: &str) -> Result<Self, ThemeLoadError> {
        serde_yaml::from_str(yaml).map_err(ThemeLoadError::Yaml)
    }

    /// Load theme from file (format detected by extension)
    pub fn from_file(path: impl AsRef<Path>) -> Result<Self, ThemeLoadError> {
        let path = path.as_ref();
        let content = std::fs::read_to_string(path)
            .map_err(ThemeLoadError::Io)?;

        match path.extension().and_then(|e| e.to_str()) {
            Some("json") => Self::from_json(&content),
            Some("toml") => Self::from_toml(&content),
            Some("yaml") | Some("yml") => {
                #[cfg(feature = "yaml")]
                return Self::from_yaml(&content);
                #[cfg(not(feature = "yaml"))]
                return Err(ThemeLoadError::UnsupportedFormat("yaml".into()));
            }
            Some(ext) => Err(ThemeLoadError::UnsupportedFormat(ext.into())),
            None => Err(ThemeLoadError::UnsupportedFormat("unknown".into())),
        }
    }

    /// Serialize theme to JSON
    pub fn to_json(&self) -> Result<String, ThemeSaveError> {
        serde_json::to_string_pretty(self).map_err(ThemeSaveError::Json)
    }

    /// Serialize theme to TOML
    pub fn to_toml(&self) -> Result<String, ThemeSaveError> {
        toml::to_string_pretty(self).map_err(ThemeSaveError::Toml)
    }

    /// Save theme to file
    pub fn to_file(&self, path: impl AsRef<Path>) -> Result<(), ThemeSaveError> {
        let path = path.as_ref();
        let content = match path.extension().and_then(|e| e.to_str()) {
            Some("json") => self.to_json()?,
            Some("toml") => self.to_toml()?,
            Some(ext) => return Err(ThemeSaveError::UnsupportedFormat(ext.into())),
            None => self.to_json()?, // Default to JSON
        };

        std::fs::write(path, content).map_err(ThemeSaveError::Io)
    }
}

#[derive(Debug, thiserror::Error)]
pub enum ThemeLoadError {
    #[error("JSON parse error: {0}")]
    Json(#[from] serde_json::Error),
    #[error("TOML parse error: {0}")]
    Toml(#[from] toml::de::Error),
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Unsupported format: {0}")]
    UnsupportedFormat(String),
}
